mapper.select:
select from doctor_info d left join sys_user u on d.user_id = u.id left join department_info dp on d.department_id = dp.id
and d.department_id = #{departmentId}
and d.status = #{status}
and (d.doctor_name like concat('%', #{keyword}, '%') or d.title like concat('%', #{keyword}, '%') or d.specialty like concat('%', #{keyword}, '%'))
order by d.id desc

mapper.update:
update doctor_info
department_id = #{departmentId}, doctor_name = #{doctorName}, title = #{title}, gender = #{gender}, specialty = #{specialty}, introduction = #{introduction}, avatar = #{avatar}, consultation_fee = #{consultationFee}, status = #{status}, visit_count = #{visitCount}, update_time = #{updateTime},
where id = #{id}
